const EgtHandicap=(function(){function roundHalfUp(x){return Math.floor(x+.5)}function courseHandicap(hi,slope,cr,par){return roundHalfUp(hi*slope/113+(cr-par))}function nineHoleCourseHandicap(hi,nineSlope,nineCr,ninePar){return roundHalfUp(hi*.5*nineSlope/113+(nineCr-ninePar))}function playingHandicap(ch,allowance){const a=typeof allowance==="number"&&allowance>=0?allowance:1;return roundHalfUp(ch*a)}function allocatePops(n,holes){if(!Array.isArray(holes)||holes.length===0)return[];if(holes.some(h=>h.si===null||h.si===void 0))return null;const m=holes.length;const count=Math.trunc(n)||0;if(count===0)return[];const sign=count<0?-1:1;const mag=Math.abs(count);const base=Math.floor(mag/m);const extra=mag%m;const out=[];holes.slice().sort((a,b)=>a.hole-b.hole).forEach(h=>{const gets=sign>0?h.si<=extra?1:0:h.si>m-extra?1:0;const strokes=(base+gets)*sign;if(strokes!==0)out.push({hole:h.hole,strokes})});return out}function popsTotal(pops){if(!Array.isArray(pops))return 0;return pops.reduce((a,p)=>a+(p.strokes||0),0)}function netOnHole(gross,popsOnHole2){if(!gross&&gross!==0)return null;return gross-(popsOnHole2||0)}function popsOnHole(pops,hole){if(!Array.isArray(pops))return 0;const found=pops.find(p=>p.hole===hole);return found?found.strokes:0}function isPermutation(arr,n){if(!Array.isArray(arr)||arr.length!==n)return false;const seen=new Set;for(const v of arr){const num=Number(v);if(!Number.isInteger(num)||num<1||num>n)return false;if(seen.has(num))return false;seen.add(num)}return true}function eighteenFromNine(nineSi){if(!isPermutation(nineSi,9)){throw new Error("9-hole stroke index must be a permutation of 1..9")}const out=new Array(18);for(let i=0;i<9;i++){out[i]=nineSi[i]*2-1;out[i+9]=nineSi[i]*2}return out}function nineHoleSi(si18){return Math.ceil(si18/2)}return{roundHalfUp,courseHandicap,nineHoleCourseHandicap,playingHandicap,allocatePops,popsTotal,netOnHole,popsOnHole,isPermutation,eighteenFromNine,nineHoleSi}})();if(typeof window!=="undefined"){Object.assign(window,{EgtHandicap})}
